var COURSE_PL_ZH = [{day: 1, title: `Pierwsze powitania`, title_native: `第一次打招呼`, focus: `Zaczynasz od najważniejszych zwrotów, których użyjesz zaraz po przylocie do Pekinu, Szanghaju albo Tajpej. Nauczysz się przywitać, pożegnać i grzecznie zwrócić się do drugiej osoby.`, vocab: [{zh: `你好`, pl: `cześć / dzień dobry`, ipa: `ni˧˩ xau˧˩`},{zh: `您好`, pl: `dzień dobry, grzecznie`, ipa: `nin˧˥ xau˧˩`},{zh: `我`, pl: `ja`, ipa: `ło˧˩`},{zh: `你`, pl: `ty`, ipa: `ni˧˩`},{zh: `他`, pl: `on`, ipa: `ta˥`},{zh: `她`, pl: `ona`, ipa: `ta˥`},{zh: `谢谢`, pl: `dziękuję`, ipa: `śje˥ śje`},{zh: `再见`, pl: `do widzenia`, ipa: `dzaj˥˩ dzjen˥˩`},{zh: `早上`, pl: `rano`, ipa: `dzao˧˩ szang˥˩`},{zh: `晚上`, pl: `wieczór`, ipa: `łan˧˩ szang˥˩`}], phrases: [{zh: `你好！`, pl: `Cześć! / Dzień dobry!`, ipa: `ni˧˩ xau˧˩`},{zh: `您好！`, pl: `Dzień dobry! grzecznie`, ipa: `nin˧˥ xau˧˩`},{zh: `谢谢你。`, pl: `Dziękuję ci.`, ipa: `śje˥ śje ni˧˩`},{zh: `再见！`, pl: `Do widzenia!`, ipa: `dzaj˥˩ dzjen˥˩`},{zh: `早上好。`, pl: `Dzień dobry rano.`, ipa: `dzao˧˩ szang˥˩ xau˧˩`},{zh: `晚上好。`, pl: `Dobry wieczór.`, ipa: `łan˧˩ szang˥˩ xau˧˩`}], grammar: `W chińskim nie odmienia się czasowników ani rzeczowników przez osoby. „我” znaczy „ja”, a czasownik po nim zostaje w tej samej formie. W podróży to bardzo praktyczne, bo możesz budować proste zdania bez martwienia się o końcówki.`, practice: [`Przywitaj recepcjonistę w hotelu, używając grzecznego zwrotu.`,`Powiedz „dziękuję ci” do osoby, która pomogła ci z bagażem.`,`Pożegnaj kierowcę taksówki.`,`Przećwicz różnicę między 你好 i 您好.`,`Napisz krótką wymianę: „dzień dobry”, „dziękuję”, „do widzenia”.`]},{day: 2, title: `Przedstawianie się`, title_native: `自我介绍`, focus: `W hostelu w Chengdu albo podczas wycieczki grupowej chcesz powiedzieć, jak masz na imię i skąd jesteś. Ten dzień uczy prostych zdań o sobie.`, vocab: [{zh: `名字`, pl: `imię`, ipa: `ming˧˥ dz`},{zh: `叫`, pl: `nazywać się`, ipa: `dziao˥˩`},{zh: `是`, pl: `być`, ipa: `szy˥˩`},{zh: `波兰`, pl: `Polska`, ipa: `bo˥ lan˧˥`},{zh: `人`, pl: `osoba / człowiek`, ipa: `żen˧˥`},{zh: `朋友`, pl: `przyjaciel`, ipa: `peng˧˥ jou`},{zh: `学生`, pl: `uczeń / student`, ipa: `śüe˧˥ szeng˥`},{zh: `游客`, pl: `turysta`, ipa: `jou˧˩ ke˥˩`},{zh: `也`, pl: `też`, ipa: `je˧˩`},{zh: `很`, pl: `bardzo`, ipa: `hen˧˩`}], phrases: [{zh: `我叫安娜。`, pl: `Nazywam się Anna.`, ipa: `ło˧˩ dziao˥˩ an˥ na`},{zh: `我是波兰人。`, pl: `Jestem Polakiem/Polką.`, ipa: `ło˧˩ szy˥˩ bo˥ lan˧˥ żen˧˥`},{zh: `你叫什么名字？`, pl: `Jak masz na imię?`, ipa: `ni˧˩ dziao˥˩ szen˧ me ming˧˥ dz`},{zh: `我是游客。`, pl: `Jestem turystą/turystką.`, ipa: `ło˧˩ szy˥˩ jou˧˩ ke˥˩`},{zh: `我也很高兴。`, pl: `Mnie też bardzo miło.`, ipa: `ło˧˩ je˧˩ hen˧˩ gao˥ śing˥˩`},{zh: `很高兴认识你。`, pl: `Miło cię poznać.`, ipa: `hen˧˩ gao˥ śing˥˩ ren˥˩ szy ni˧˩`}], grammar: `„是” działa jak polskie „jestem/jesteś/jest”, ale nie zmienia formy. Możesz powiedzieć „我是波兰人” i „你是波兰人吗？” bez odmiany czasownika. Pytanie często tworzy się przez dodanie „吗” na końcu zdania.`, practice: [`Powiedz po chińsku, jak masz na imię.`,`Powiedz, że jesteś z Polski.`,`Zapytaj kogoś o imię.`,`Powiedz „miło cię poznać” nowo poznanej osobie.`,`Zmień zdanie „我是游客” na pytanie z 吗.`]},{day: 3, title: `Tak, nie i proste odpowiedzi`, title_native: `是，不是，简单回答`, focus: `W podróży często trzeba szybko potwierdzić rezerwację, kierunek albo zamówienie. Nauczysz się odpowiadać „tak”, „nie”, „dobrze” i „nie rozumiem”.`, vocab: [{zh: `是`, pl: `tak / być`, ipa: `szy˥˩`},{zh: `不是`, pl: `nie jest / nie`, ipa: `bu˧˥ szy˥˩`},{zh: `对`, pl: `zgadza się`, ipa: `duej˥˩`},{zh: `不对`, pl: `nie zgadza się`, ipa: `bu˧˥ duej˥˩`},{zh: `好`, pl: `dobrze`, ipa: `xau˧˩`},{zh: `不好`, pl: `niedobrze`, ipa: `bu˥˩ xau˧˩`},{zh: `可以`, pl: `można / okej`, ipa: `ke˧˩ ji˧˩`},{zh: `不可以`, pl: `nie można`, ipa: `bu˥˩ ke˧˩ ji˧˩`},{zh: `明白`, pl: `rozumieć`, ipa: `ming˧˥ baj˧˥`},{zh: `懂`, pl: `rozumieć`, ipa: `dong˧˩`}], phrases: [{zh: `是的。`, pl: `Tak.`, ipa: `szy˥˩ de`},{zh: `不是。`, pl: `Nie.`, ipa: `bu˧˥ szy˥˩`},{zh: `对。`, pl: `Zgadza się.`, ipa: `duej˥˩`},{zh: `不对。`, pl: `Nie zgadza się.`, ipa: `bu˧˥ duej˥˩`},{zh: `我不明白。`, pl: `Nie rozumiem.`, ipa: `ło˧˩ bu˥˩ ming˧˥ baj˧˥`},{zh: `可以吗？`, pl: `Czy można? / Czy to okej?`, ipa: `ke˧˩ ji˧˩ ma`}], grammar: `„不” oznacza zaprzeczenie i stawia się je przed czasownikiem lub przymiotnikiem. Na przykład „好” to „dobrze”, a „不好” to „niedobrze”. W mowie podróżnej wystarczy często krótka odpowiedź: „对” albo „不对”.`, practice: [`Potwierdź, że twoje nazwisko na rezerwacji jest poprawne.`,`Powiedz, że nie rozumiesz.`,`Zapytaj, czy można tutaj usiąść.`,`Odpowiedz „nie zgadza się” na błędną cenę.`,`Stwórz trzy pary: forma twierdząca i forma z 不.`]},{day: 4, title: `Liczby od 0 do 10`, title_native: `零到十`, focus: `W sklepie, metrze i restauracji liczby pojawiają się wszędzie. Dzisiaj nauczysz się podstawowych cyfr potrzebnych do płacenia i zamawiania.`, vocab: [{zh: `零`, pl: `zero`, ipa: `ling˧˥`},{zh: `一`, pl: `jeden`, ipa: `ji˥`},{zh: `二`, pl: `dwa`, ipa: `ar˥˩`},{zh: `三`, pl: `trzy`, ipa: `san˥`},{zh: `四`, pl: `cztery`, ipa: `sy˥˩`},{zh: `五`, pl: `pięć`, ipa: `u˧˩`},{zh: `六`, pl: `sześć`, ipa: `lioł˥˩`},{zh: `七`, pl: `siedem`, ipa: `ci˥`},{zh: `八`, pl: `osiem`, ipa: `ba˥`},{zh: `九`, pl: `dziewięć`, ipa: `dzioł˧˩`}], phrases: [{zh: `一个。`, pl: `Jedna sztuka.`, ipa: `ji˧˥ ge`},{zh: `两个。`, pl: `Dwie sztuki.`, ipa: `liang˧˩ ge`},{zh: `我要三个。`, pl: `Chcę trzy.`, ipa: `ło˧˩ jao˥˩ san˥ ge`},{zh: `多少钱？`, pl: `Ile to kosztuje?`, ipa: `duo˥ szao˧˩ cien˧˥`},{zh: `五块钱。`, pl: `Pięć juanów.`, ipa: `u˧˩ kuaj˥˩ cien˧˥`},{zh: `一、二、三。`, pl: `Raz, dwa, trzy.`, ipa: `ji˥ ar˥˩ san˥`}], grammar: `Przy liczeniu rzeczy bardzo często używa się klasyfikatora „个”. Po polsku mówimy po prostu „dwa bilety”, ale po chińsku często pojawia się struktura liczba + klasyfikator + rzeczownik. Na początku możesz używać „个” jako najbardziej ogólnego klasyfikatora.`, practice: [`Policz od 0 do 9 na głos.`,`Zamów jedną wodę, używając 一个.`,`Powiedz, że chcesz trzy sztuki.`,`Zapytaj o cenę pamiątki.`,`Napisz ceny: 5 juanów, 8 juanów, 9 juanów.`]},{day: 5, title: `Liczby większe i ceny`, title_native: `更大的数字和价格`, focus: `W nocnym markecie w Tajpej albo na bazarze w Xi’an ceny nie kończą się na dziesięciu. Nauczysz się mówić o dziesiątkach i prostych kwotach.`, vocab: [{zh: `十`, pl: `dziesięć`, ipa: `szy˧˥`},{zh: `十一`, pl: `jedenaście`, ipa: `szy˧˥ ji˥`},{zh: `十二`, pl: `dwanaście`, ipa: `szy˧˥ ar˥˩`},{zh: `二十`, pl: `dwadzieścia`, ipa: `ar˥˩ szy˧˥`},{zh: `三十`, pl: `trzydzieści`, ipa: `san˥ szy˧˥`},{zh: `百`, pl: `sto`, ipa: `baj˧˩`},{zh: `块`, pl: `juan, potocznie`, ipa: `kuaj˥˩`},{zh: `元`, pl: `juan, formalnie`, ipa: `jüen˧˥`},{zh: `毛`, pl: `dziesiąta część juana`, ipa: `mao˧˥`},{zh: `贵`, pl: `drogi`, ipa: `guej˥˩`}], phrases: [{zh: `十块钱。`, pl: `Dziesięć juanów.`, ipa: `szy˧˥ kuaj˥˩ cien˧˥`},{zh: `二十块钱。`, pl: `Dwadzieścia juanów.`, ipa: `ar˥˩ szy˧˥ kuaj˥˩ cien˧˥`},{zh: `太贵了。`, pl: `Za drogo.`, ipa: `taj˥˩ guej˥˩ le`},{zh: `便宜一点。`, pl: `Trochę taniej.`, ipa: `pien˧˥ ji˧ i˥ dien˧˩`},{zh: `我要这个。`, pl: `Chcę to.`, ipa: `ło˧˩ jao˥˩ dże˥˩ ge`},{zh: `多少钱一个？`, pl: `Ile za jedną sztukę?`, ipa: `duo˥ szao˧˩ cien˧˥ ji˧˥ ge`}], grammar: `„太…了” oznacza „zbyt…” albo „bardzo…”, zależnie od tonu sytuacji. „太贵了” to użyteczny zwrot przy zakupach: „za drogo”. W Chinach kontynentalnych potoczne „块” jest częstsze w mowie niż formalne „元”.`, practice: [`Powiedz po chińsku: 10, 12, 20, 30.`,`Zapytaj, ile kosztuje jedna sztuka.`,`Powiedz, że coś jest za drogie.`,`Poproś o trochę niższą cenę.`,`Ułóż mini-dialog przy stoisku z pamiątkami.`]},{day: 6, title: `Dni, godziny i umawianie się`, title_native: `日期，时间，约定`, focus: `W Szanghaju chcesz sprawdzić godzinę odjazdu pociągu albo umówić się z przewodnikiem. Ten dzień uczy podstaw czasu i prostych pytań o godzinę.`, vocab: [{zh: `今天`, pl: `dzisiaj`, ipa: `dzin˥ tien˥`},{zh: `明天`, pl: `jutro`, ipa: `ming˧˥ tien˥`},{zh: `昨天`, pl: `wczoraj`, ipa: `dzuo˧˥ tien˥`},{zh: `现在`, pl: `teraz`, ipa: `śien˥˩ dzaj˥˩`},{zh: `点`, pl: `godzina`, ipa: `dien˧˩`},{zh: `分钟`, pl: `minuta`, ipa: `fen˥ dżong˥`},{zh: `半`, pl: `pół`, ipa: `ban˥˩`},{zh: `早`, pl: `wcześnie`, ipa: `dzao˧˩`},{zh: `晚`, pl: `późno`, ipa: `łan˧˩`},{zh: `时间`, pl: `czas`, ipa: `szy˧˥ dzien˥`}], phrases: [{zh: `现在几点？`, pl: `Która jest godzina?`, ipa: `śien˥˩ dzaj˥˩ dzi˧˩ dien˧˩`},{zh: `三点。`, pl: `Trzecia.`, ipa: `san˥ dien˧˩`},{zh: `三点半。`, pl: `Trzecia trzydzieści.`, ipa: `san˥ dien˧˩ ban˥˩`},{zh: `今天可以吗？`, pl: `Czy dzisiaj można?`, ipa: `dzin˥ tien˥ ke˧˩ ji˧˩ ma`},{zh: `明天见。`, pl: `Do zobaczenia jutro.`, ipa: `ming˧˥ tien˥ dzjen˥˩`},{zh: `时间不够。`, pl: `Nie ma dość czasu.`, ipa: `szy˧˥ dzien˥ bu˧˥ gou˥˩`}], grammar: `Godzinę podaje się liczba + 点, na przykład „三点”. „半” dodane po godzinie oznacza „wpół do / trzydzieści po”, czyli „三点半” to 3:30. Pytanie „几点？” znaczy „która godzina?” albo „o której?”.`, practice: [`Zapytaj przechodnia, która jest godzina.`,`Powiedz, że spotkanie jest o 3:30.`,`Umów się z kimś na jutro.`,`Powiedz, że dzisiaj jest za mało czasu.`,`Zapisz trzy godziny po chińsku.`]},{day: 7, title: `Prośby i uprzejmość`, title_native: `请求和礼貌`, focus: `W podróży uprzejmość pomaga w hotelu, restauracji i metrze. Nauczysz się mówić „proszę”, „przepraszam” i łagodnie prosić o pomoc.`, vocab: [{zh: `请`, pl: `proszę`, ipa: `cing˧˩`},{zh: `麻烦`, pl: `kłopot / proszę o pomoc`, ipa: `ma˧˥ fan`},{zh: `不好意思`, pl: `przepraszam / wybacz`, ipa: `bu˥˩ xau˧˩ ji˥˩ sy`},{zh: `对不起`, pl: `przepraszam`, ipa: `duej˥˩ bu˥˩ ci˧˩`},{zh: `没关系`, pl: `nic nie szkodzi`, ipa: `mej˧˥ guan˥ śi`},{zh: `帮忙`, pl: `pomagać`, ipa: `bang˥ mang˧˥`},{zh: `给`, pl: `dawać`, ipa: `gej˧˩`},{zh: `拿`, pl: `wziąć / podać`, ipa: `na˧˥`},{zh: `看`, pl: `patrzeć`, ipa: `kan˥˩`},{zh: `一下`, pl: `przez chwilę`, ipa: `ji˧˥ śia˥˩`}], phrases: [{zh: `请帮忙。`, pl: `Proszę pomóc.`, ipa: `cing˧˩ bang˥ mang˧˥`},{zh: `麻烦你。`, pl: `Przepraszam za kłopot / proszę.`, ipa: `ma˧˥ fan ni˧˩`},{zh: `不好意思。`, pl: `Przepraszam / wybacz.`, ipa: `bu˥˩ xau˧˩ ji˥˩ sy`},{zh: `可以帮我吗？`, pl: `Czy możesz mi pomóc?`, ipa: `ke˧˩ ji˧˩ bang˥ ło˧˩ ma`},{zh: `请给我这个。`, pl: `Proszę dać mi to.`, ipa: `cing˧˩ gej˧˩ ło˧˩ dże˥˩ ge`},{zh: `看一下。`, pl: `Proszę spojrzeć.`, ipa: `kan˥˩ ji˧˥ śia˥˩`}], grammar: `„请” przed czasownikiem dodaje uprzejmości, podobnie jak polskie „proszę”. „一下” łagodzi prośbę i sugeruje krótką czynność, na przykład „看一下” to „proszę spojrzeć na chwilę”. W codziennych sytuacjach brzmi to naturalnie i mniej rozkazująco.`, practice: [`Poproś pracownika metra o pomoc.`,`Powiedz „przepraszam” komuś, komu zasłoniłeś przejście.`,`Poproś sprzedawcę, żeby podał ci ten produkt.`,`Użyj 看一下 przy pokazywaniu mapy.`,`Zbuduj trzy uprzejme prośby z 请.`]},{day: 8, title: `Na lotnisku`, title_native: `在机场`, focus: `Po przylocie do Pekinu lub Hongkongu musisz przejść kontrolę, odebrać bagaż i znaleźć wyjście. Ten dzień skupia się na słownictwie lotniskowym.`, vocab: [{zh: `机场`, pl: `lotnisko`, ipa: `dzi˥ czang˧˥`},{zh: `护照`, pl: `paszport`, ipa: `xu˥˩ dżao˥˩`},{zh: `签证`, pl: `wiza`, ipa: `cien˥ dżeng˥˩`},{zh: `行李`, pl: `bagaż`, ipa: `śing˧˥ li˧˩`},{zh: `出口`, pl: `wyjście`, ipa: `chu˥ koł˧˩`},{zh: `入口`, pl: `wejście`, ipa: `żu˥˩ koł˧˩`},{zh: `海关`, pl: `odprawa celna`, ipa: `xaj˧˩ guan˥`},{zh: `飞机`, pl: `samolot`, ipa: `fej˥ dzi˥`},{zh: `到达`, pl: `przylot / dotrzeć`, ipa: `dao˥˩ da˧˥`},{zh: `登机牌`, pl: `karta pokładowa`, ipa: `deng˥ dzi˥ paj˧˥`}], phrases: [{zh: `我的护照在这里。`, pl: `Mój paszport jest tutaj.`, ipa: `ło˧˩ de xu˥˩ dżao˥˩ dzaj˥˩ dże˥˩ li`},{zh: `行李在哪里？`, pl: `Gdzie jest bagaż?`, ipa: `śing˧˥ li˧˩ dzaj˥˩ na˧˩ li`},{zh: `出口在哪里？`, pl: `Gdzie jest wyjście?`, ipa: `chu˥ koł˧˩ dzaj˥˩ na˧˩ li`},{zh: `这是我的登机牌。`, pl: `To jest moja karta pokładowa.`, ipa: `dże˥˩ szy˥˩ ło˧˩ de deng˥ dzi˥ paj˧˥`},{zh: `我没有签证。`, pl: `Nie mam wizy.`, ipa: `ło˧˩ mej˧˥ jou˧˩ cien˥ dżeng˥˩`},{zh: `飞机到了吗？`, pl: `Czy samolot przyleciał?`, ipa: `fej˥ dzi˥ dao˥˩ le ma`}], grammar: `„在” oznacza „być w / być przy / znajdować się”. Pytanie „在哪里？” znaczy „gdzie jest?”. To jedna z najważniejszych struktur podróżnych: rzecz + 在哪里?`, practice: [`Zapytaj, gdzie jest wyjście.`,`Powiedz, że twój paszport jest tutaj.`,`Zapytaj, gdzie odebrać bagaż.`,`Pokaż kartę pokładową i nazwij ją po chińsku.`,`Ułóż dwa pytania ze strukturą 在哪里.`]},{day: 9, title: `Hotel i zameldowanie`, title_native: `酒店入住`, focus: `W hotelu w Kantonie albo Tajpej potrzebujesz podać rezerwację i zapytać o pokój. Nauczysz się zwrotów do recepcji.`, vocab: [{zh: `酒店`, pl: `hotel`, ipa: `dzioł˧˩ dien˥˩`},{zh: `房间`, pl: `pokój`, ipa: `fang˧˥ dzien˥`},{zh: `预订`, pl: `rezerwacja`, ipa: `jü˥˩ ding˥˩`},{zh: `入住`, pl: `zameldowanie`, ipa: `żu˥˩ dżu˥˩`},{zh: `退房`, pl: `wymeldowanie`, ipa: `tuej˥˩ fang˧˥`},{zh: `钥匙`, pl: `klucz`, ipa: `jao˥˩ szy`},{zh: `电梯`, pl: `winda`, ipa: `dien˥˩ ti˥`},{zh: `楼`, pl: `piętro / budynek`, ipa: `loł˧˥`},{zh: `前台`, pl: `recepcja`, ipa: `cien˧˥ taj˧˥`},{zh: `早餐`, pl: `śniadanie`, ipa: `dzao˧˩ can˥`}], phrases: [{zh: `我有预订。`, pl: `Mam rezerwację.`, ipa: `ło˧˩ jou˧˩ jü˥˩ ding˥˩`},{zh: `我要入住。`, pl: `Chcę się zameldować.`, ipa: `ło˧˩ jao˥˩ żu˥˩ dżu˥˩`},{zh: `房间在哪里？`, pl: `Gdzie jest pokój?`, ipa: `fang˧˥ dzien˥ dzaj˥˩ na˧˩ li`},{zh: `早餐几点？`, pl: `O której jest śniadanie?`, ipa: `dzao˧˩ can˥ dzi˧˩ dien˧˩`},{zh: `电梯在哪里？`, pl: `Gdzie jest winda?`, ipa: `dien˥˩ ti˥ dzaj˥˩ na˧˩ li`},{zh: `我可以退房吗？`, pl: `Czy mogę się wymeldować?`, ipa: `ło˧˩ ke˧˩ ji˧˩ tuej˥˩ fang˧˥ ma`}], grammar: `„有” oznacza „mieć” albo „istnieć”. „我有预订” dosłownie znaczy „ja mam rezerwację”. Zaprzeczenie to „没有”, więc „我没有预订” znaczy „nie mam rezerwacji”.`, practice: [`Powiedz recepcjoniście, że masz rezerwację.`,`Zapytaj, gdzie jest winda.`,`Zapytaj, o której jest śniadanie.`,`Powiedz, że chcesz się zameldować.`,`Zmień zdanie 我有预订 na formę przeczącą.`]},{day: 10, title: `Pokój hotelowy i problemy`, title_native: `酒店房间和问题`, focus: `Czasem w pokoju hotelowym nie działa klimatyzacja albo brakuje ręcznika. Ten dzień uczy zgłaszania prostych problemów.`, vocab: [{zh: `空调`, pl: `klimatyzacja`, ipa: `kong˥ tiao˧˥`},{zh: `热水`, pl: `ciepła woda`, ipa: `że˥˩ szuej˧˩`},{zh: `毛巾`, pl: `ręcznik`, ipa: `mao˧˥ dzin˥`},{zh: `床`, pl: `łóżko`, ipa: `czang˧˥`},{zh: `厕所`, pl: `toaleta`, ipa: `ce˥˩ suo˧˩`},{zh: `坏了`, pl: `zepsuło się`, ipa: `xuaj˥˩ le`},{zh: `没有`, pl: `nie ma / nie mieć`, ipa: `mej˧˥ jou˧˩`},{zh: `需要`, pl: `potrzebować`, ipa: `śü˥ jao˥˩`},{zh: `换`, pl: `zmienić / wymienić`, ipa: `xuan˥˩`},{zh: `安静`, pl: `cichy`, ipa: `an˥ dzing˥˩`}], phrases: [{zh: `空调坏了。`, pl: `Klimatyzacja się zepsuła.`, ipa: `kong˥ tiao˧˥ xuaj˥˩ le`},{zh: `没有热水。`, pl: `Nie ma ciepłej wody.`, ipa: `mej˧˥ jou˧˩ że˥˩ szuej˧˩`},{zh: `我需要毛巾。`, pl: `Potrzebuję ręcznika.`, ipa: `ło˧˩ śü˥ jao˥˩ mao˧˥ dzin˥`},{zh: `可以换房间吗？`, pl: `Czy można zmienić pokój?`, ipa: `ke˧˩ ji˧˩ xuan˥˩ fang˧˥ dzien˥ ma`},{zh: `房间很吵。`, pl: `Pokój jest bardzo głośny.`, ipa: `fang˧˥ dzien˥ hen˧˩ czau˧˩`},{zh: `我想要安静的房间。`, pl: `Chcę cichy pokój.`, ipa: `ło˧˩ śiang˧˩ jao˥˩ an˥ dzing˥˩ de fang˧˥ dzien˥`}], grammar: `„了” po czasowniku często pokazuje zmianę sytuacji lub zakończenie zdarzenia. „坏了” znaczy, że coś „się zepsuło”. W hotelu możesz użyć krótkiego zdania rzecz + 坏了, na przykład „空调坏了”.`, practice: [`Powiedz, że klimatyzacja się zepsuła.`,`Poproś o ręcznik.`,`Powiedz, że nie ma ciepłej wody.`,`Zapytaj, czy można zmienić pokój.`,`Opisz pokój jako cichy albo głośny.`]},{day: 11, title: `Zamawianie kawy i napojów`, title_native: `点咖啡和饮料`, focus: `W kawiarni w Szanghaju lub Tajpej chcesz zamówić kawę, herbatę albo wodę. Nauczysz się prostych zamówień i pytań o rozmiar.`, vocab: [{zh: `咖啡`, pl: `kawa`, ipa: `ka˥ fej˥`},{zh: `茶`, pl: `herbata`, ipa: `cza˧˥`},{zh: `水`, pl: `woda`, ipa: `szuej˧˩`},{zh: `牛奶`, pl: `mleko`, ipa: `nioł˧˥ naj˧˩`},{zh: `糖`, pl: `cukier`, ipa: `tang˧˥`},{zh: `冰`, pl: `lód`, ipa: `bing˥`},{zh: `热`, pl: `gorący`, ipa: `że˥˩`},{zh: `冷`, pl: `zimny`, ipa: `leng˧˩`},{zh: `杯`, pl: `kubek / szklanka`, ipa: `bej˥`},{zh: `大`, pl: `duży`, ipa: `da˥˩`}], phrases: [{zh: `我要一杯咖啡。`, pl: `Chcę jedną kawę.`, ipa: `ło˧˩ jao˥˩ ji˥ bej˥ ka˥ fej˥`},{zh: `不要糖。`, pl: `Bez cukru.`, ipa: `bu˥˩ jao˥˩ tang˧˥`},{zh: `不要冰。`, pl: `Bez lodu.`, ipa: `bu˥˩ jao˥˩ bing˥`},{zh: `我要热茶。`, pl: `Chcę gorącą herbatę.`, ipa: `ło˧˩ jao˥˩ że˥˩ cza˧˥`},{zh: `大杯。`, pl: `Duży kubek.`, ipa: `da˥˩ bej˥`},{zh: `可以外带吗？`, pl: `Czy można na wynos?`, ipa: `ke˧˩ ji˧˩ łaj˥˩ daj˥˩ ma`}], grammar: `„要” oznacza „chcieć” i świetnie działa przy zamawianiu. „我要一杯咖啡” to naturalne „poproszę kawę”. „不要” oznacza „nie chcę” albo „bez”, na przykład „不要糖”.`, practice: [`Zamów jedną kawę.`,`Poproś herbatę bez cukru.`,`Zamów zimną wodę bez lodu.`,`Zapytaj, czy kawa może być na wynos.`,`Stwórz dwa zdania z 我要 i dwa z 不要.`]},{day: 12, title: `Jedzenie w restauracji`, title_native: `在餐厅吃饭`, focus: `W restauracji w Chengdu, znanej z ostrych potraw, chcesz poprosić o menu i zamówić jedzenie. Dzisiaj ćwiczysz podstawy restauracyjne.`, vocab: [{zh: `餐厅`, pl: `restauracja`, ipa: `can˥ ting˥`},{zh: `菜单`, pl: `menu`, ipa: `caj˥˩ dan˥`},{zh: `米饭`, pl: `ryż`, ipa: `mi˧˩ fan˥˩`},{zh: `面条`, pl: `makaron`, ipa: `mien˥˩ tiao˧˥`},{zh: `鸡肉`, pl: `kurczak`, ipa: `dzi˥ żoł˥˩`},{zh: `牛肉`, pl: `wołowina`, ipa: `nioł˧˥ żoł˥˩`},{zh: `鱼`, pl: `ryba`, ipa: `jü˧˥`},{zh: `蔬菜`, pl: `warzywa`, ipa: `szu˥ caj˥˩`},{zh: `辣`, pl: `ostry`, ipa: `la˥˩`},{zh: `好吃`, pl: `smaczny`, ipa: `xau˧˩ czy˥`}], phrases: [{zh: `请给我菜单。`, pl: `Proszę dać mi menu.`, ipa: `cing˧˩ gej˧˩ ło˧˩ caj˥˩ dan˥`},{zh: `我要米饭。`, pl: `Chcę ryż.`, ipa: `ło˧˩ jao˥˩ mi˧˩ fan˥˩`},{zh: `这个辣吗？`, pl: `Czy to jest ostre?`, ipa: `dże˥˩ ge la˥˩ ma`},{zh: `不要太辣。`, pl: `Nie za ostre.`, ipa: `bu˥˩ jao˥˩ taj˥˩ la˥˩`},{zh: `很好吃。`, pl: `Bardzo smaczne.`, ipa: `hen˧˩ xau˧˩ czy˥`},{zh: `买单。`, pl: `Rachunek proszę.`, ipa: `maj˧˩ dan˥`}], grammar: `Przymiotniki w chińskim często działają jak czasowniki opisowe. „好吃” dosłownie znaczy „dobrze jeść”, ale używa się go jako „smaczne”. Możesz powiedzieć „很好吃”, aby pochwalić jedzenie.`, practice: [`Poproś o menu.`,`Zapytaj, czy danie jest ostre.`,`Zamów ryż i kurczaka.`,`Powiedz, że nie chcesz zbyt ostrego jedzenia.`,`Poproś o rachunek.`]},{day: 13, title: `Specjalne potrzeby żywieniowe`, title_native: `特殊饮食需求`, focus: `Jeśli masz alergię albo nie jesz mięsa, musisz umieć powiedzieć to jasno. Ten dzień pomaga bezpiecznie zamawiać jedzenie w chińskojęzycznych miejscach.`, vocab: [{zh: `过敏`, pl: `alergia`, ipa: `guo˥˩ min˧˩`},{zh: `花生`, pl: `orzeszki ziemne`, ipa: `xua˥ szeng˥`},{zh: `海鲜`, pl: `owoce morza`, ipa: `xaj˧˩ śien˥`},{zh: `肉`, pl: `mięso`, ipa: `żoł˥˩`},{zh: `素`, pl: `wegetariański`, ipa: `su˥˩`},{zh: `鸡蛋`, pl: `jajko`, ipa: `dzi˥ dan˥˩`},{zh: `奶`, pl: `mleko / nabiał`, ipa: `naj˧˩`},{zh: `不能`, pl: `nie móc`, ipa: `bu˥˩ neng˧˥`},{zh: `吃`, pl: `jeść`, ipa: `czy˥`},{zh: `安全`, pl: `bezpieczny`, ipa: `an˥ czüen˧˥`}], phrases: [{zh: `我对花生过敏。`, pl: `Mam alergię na orzeszki ziemne.`, ipa: `ło˧˩ duej˥˩ xua˥ szeng˥ guo˥˩ min˧˩`},{zh: `我不能吃海鲜。`, pl: `Nie mogę jeść owoców morza.`, ipa: `ło˧˩ bu˥˩ neng˧˥ czy˥ xaj˧˩ śien˥`},{zh: `有肉吗？`, pl: `Czy jest mięso?`, ipa: `jou˧˩ żoł˥˩ ma`},{zh: `我要素的。`, pl: `Chcę wegetariańskie.`, ipa: `ło˧˩ jao˥˩ su˥˩ de`},{zh: `这个安全吗？`, pl: `Czy to jest bezpieczne?`, ipa: `dże˥˩ ge an˥ czüen˧˥ ma`},{zh: `请不要放鸡蛋。`, pl: `Proszę nie dodawać jajka.`, ipa: `cing˧˩ bu˥˩ jao˥˩ fang˥˩ dzi˥ dan˥˩`}], grammar: `„不能” oznacza „nie móc” i jest ważniejsze niż samo „不吃”, gdy chodzi o alergie. „我不能吃海鲜” brzmi jasno i poważnie. „请不要放…” oznacza „proszę nie dodawać…”.`, practice: [`Powiedz, że masz alergię na orzeszki ziemne.`,`Zapytaj, czy danie zawiera mięso.`,`Poproś o wersję wegetariańską.`,`Powiedz, że nie możesz jeść owoców morza.`,`Poproś, żeby nie dodawano jajka.`]},{day: 14, title: `Ulica, adresy i kierunki`, title_native: `街道，地址，方向`, focus: `W dużych miastach, takich jak Szanghaj czy Hongkong, trzeba umieć zapytać o drogę. Dzisiaj poznasz podstawowe kierunki i słowa adresowe.`, vocab: [{zh: `路`, pl: `ulica / droga`, ipa: `lu˥˩`},{zh: `街`, pl: `ulica`, ipa: `dzie˥`},{zh: `地址`, pl: `adres`, ipa: `di˥˩ dży˧˩`},{zh: `这里`, pl: `tutaj`, ipa: `dże˥˩ li`},{zh: `那里`, pl: `tam`, ipa: `na˥˩ li`},{zh: `左边`, pl: `lewa strona`, ipa: `dzuo˧˩ bien˥`},{zh: `右边`, pl: `prawa strona`, ipa: `joł˥˩ bien˥`},{zh: `前面`, pl: `z przodu / przed`, ipa: `cien˧˥ mien˥˩`},{zh: `后面`, pl: `z tyłu / za`, ipa: `xoł˥˩ mien˥˩`},{zh: `旁边`, pl: `obok`, ipa: `pang˧˥ bien˥`}], phrases: [{zh: `这个地址在哪里？`, pl: `Gdzie jest ten adres?`, ipa: `dże˥˩ ge di˥˩ dży˧˩ dzaj˥˩ na˧˩ li`},{zh: `往左走。`, pl: `Idź w lewo.`, ipa: `łang˧˩ dzuo˧˩ dzoł˧˩`},{zh: `往右走。`, pl: `Idź w prawo.`, ipa: `łang˧˩ joł˥˩ dzoł˧˩`},{zh: `一直走。`, pl: `Idź prosto.`, ipa: `ji˥ dży˧˥ dzoł˧˩`},{zh: `在前面。`, pl: `Jest z przodu.`, ipa: `dzaj˥˩ cien˧˥ mien˥˩`},{zh: `在旁边。`, pl: `Jest obok.`, ipa: `dzaj˥˩ pang˧˥ bien˥`}], grammar: `„往” wskazuje kierunek ruchu: „往左走” to „idź w lewo”. „在” wskazuje położenie: „在旁边” to „jest obok”. W pytaniach o drogę połączysz oba typy zdań bardzo często.`, practice: [`Zapytaj, gdzie jest podany adres.`,`Powiedz komuś, żeby szedł prosto.`,`Zrozum odpowiedź „w prawo, potem prosto”.`,`Opisz hotel jako „obok restauracji”.`,`Ułóż trzy zdania z 在: tutaj, tam, obok.`]},{day: 15, title: `Metro i transport publiczny`, title_native: `地铁和公共交通`, focus: `Metro w Pekinie, Szanghaju i Tajpej jest szybkie, ale wymaga znajomości kilku słów. Nauczysz się kupować bilet i pytać o linię.`, vocab: [{zh: `地铁`, pl: `metro`, ipa: `di˥˩ tie˧˩`},{zh: `站`, pl: `stacja`, ipa: `dżan˥˩`},{zh: `票`, pl: `bilet`, ipa: `piao˥˩`},{zh: `线`, pl: `linia`, ipa: `śien˥˩`},{zh: `公交车`, pl: `autobus miejski`, ipa: `gong˥ dziao˥ cze˥`},{zh: `车`, pl: `pojazd / auto`, ipa: `cze˥`},{zh: `去`, pl: `jechać / iść do`, ipa: `ciü˥˩`},{zh: `到`, pl: `do / dotrzeć`, ipa: `dao˥˩`},{zh: `换乘`, pl: `przesiadka`, ipa: `xuan˥˩ czeng˧˥`},{zh: `出口`, pl: `wyjście`, ipa: `chu˥ koł˧˩`}], phrases: [{zh: `我要一张票。`, pl: `Chcę jeden bilet.`, ipa: `ło˧˩ jao˥˩ ji˥ dżang˥ piao˥˩`},{zh: `去市中心。`, pl: `Do centrum miasta.`, ipa: `ciü˥˩ szy˥˩ dżong˥ śin˥`},{zh: `这条线到吗？`, pl: `Czy ta linia tam jedzie?`, ipa: `dże˥˩ tiao˧˥ śien˥˩ dao˥˩ ma`},{zh: `在哪里换乘？`, pl: `Gdzie się przesiąść?`, ipa: `dzaj˥˩ na˧˩ li xuan˥˩ czeng˧˥`},{zh: `下一站是什么？`, pl: `Jaka jest następna stacja?`, ipa: `śia˥˩ ji˥ dżan˥˩ szy˥˩ szen˧ me`},{zh: `我坐地铁。`, pl: `Jadę metrem.`, ipa: `ło˧˩ dzuo˥˩ di˥˩ tie˧˩`}], grammar: `Do biletów często używa się klasyfikatora „张”, szczególnie dla płaskich rzeczy jak bilety, kartki i dokumenty. „一张票” to „jeden bilet”. Dla linii metra używa się „条”: „这条线”.`, practice: [`Poproś o jeden bilet do centrum.`,`Zapytaj, gdzie się przesiąść.`,`Zapytaj, czy ta linia jedzie do twojej stacji.`,`Powiedz, że jedziesz metrem.`,`Przećwicz różnicę między 一张票 i 这条线.`]},{day: 16, title: `Taksówka i aplikacje przewozowe`, title_native: `出租车和打车软件`, focus: `W Chinach kontynentalnych często używa się aplikacji przewozowych, ale podstawowe zwroty do kierowcy nadal są ważne. Dzisiaj uczysz się mówić dokąd jedziesz i jak płacisz.`, vocab: [{zh: `出租车`, pl: `taksówka`, ipa: `chu˥ dzu˥ cze˥`},{zh: `司机`, pl: `kierowca`, ipa: `sy˥ dzi˥`},{zh: `地址`, pl: `adres`, ipa: `di˥˩ dży˧˩`},{zh: `酒店`, pl: `hotel`, ipa: `dzioł˧˩ dien˥˩`},{zh: `火车站`, pl: `dworzec kolejowy`, ipa: `xuo˧˩ cze˥ dżan˥˩`},{zh: `机场`, pl: `lotnisko`, ipa: `dzi˥ czang˧˥`},{zh: `快`, pl: `szybko`, ipa: `kuaj˥˩`},{zh: `慢`, pl: `wolno`, ipa: `man˥˩`},{zh: `停车`, pl: `zatrzymać samochód`, ipa: `ting˧˥ cze˥`},{zh: `扫码`, pl: `skanować kod`, ipa: `sao˧˩ mao˧˩`}], phrases: [{zh: `请去这个地址。`, pl: `Proszę jechać pod ten adres.`, ipa: `cing˧˩ ciü˥˩ dże˥˩ ge di˥˩ dży˧˩`},{zh: `去机场。`, pl: `Na lotnisko.`, ipa: `ciü˥˩ dzi˥ czang˧˥`},{zh: `请慢一点。`, pl: `Proszę wolniej.`, ipa: `cing˧˩ man˥˩ ji˥ dien˧˩`},{zh: `在这里停车。`, pl: `Proszę zatrzymać tutaj.`, ipa: `dzaj˥˩ dże˥˩ li ting˧˥ cze˥`},{zh: `可以扫码付款吗？`, pl: `Czy mogę zapłacić skanem kodu?`, ipa: `ke˧˩ ji˧˩ sao˧˩ mao˧˩ fu˥˩ kuan˧˩ ma`},{zh: `多少钱？`, pl: `Ile kosztuje?`, ipa: `duo˥ szao˧˩ cien˧˥`}], grammar: `„请去…” to bardzo prosta i grzeczna forma: „proszę jechać do…”. „在这里” oznacza „tutaj”, więc „在这里停车” jest naturalne w taksówce. W wielu miejscach płatność kodem QR jest bardzo popularna, dlatego „扫码付款” jest praktycznym zwrotem.`, practice: [`Powiedz kierowcy, żeby jechał na lotnisko.`,`Poproś, żeby zatrzymał się tutaj.`,`Zapytaj, czy można zapłacić kodem QR.`,`Poproś kierowcę, żeby jechał wolniej.`,`Ułóż dialog z kierowcą od wejścia do zapłaty.`]},{day: 17, title: `Pociąg i podróże między miastami`, title_native: `火车和城市之间旅行`, focus: `Chińskie szybkie pociągi są popularne na trasach między miastami, na przykład Pekin–Szanghaj. Nauczysz się mówić o dworcu, bilecie i czasie odjazdu.`, vocab: [{zh: `火车`, pl: `pociąg`, ipa: `xuo˧˩ cze˥`},{zh: `高铁`, pl: `szybka kolej`, ipa: `gao˥ tie˧˩`},{zh: `车站`, pl: `stacja / dworzec`, ipa: `cze˥ dżan˥˩`},{zh: `车票`, pl: `bilet kolejowy`, ipa: `cze˥ piao˥˩`},{zh: `座位`, pl: `miejsce siedzące`, ipa: `dzuo˥˩ łej˥˩`},{zh: `出发`, pl: `odjazd`, ipa: `chu˥ fa˥`},{zh: `到达`, pl: `przyjazd`, ipa: `dao˥˩ da˧˥`},{zh: `晚点`, pl: `opóźnienie`, ipa: `łan˧˩ dien˧˩`},{zh: `检票`, pl: `kontrola biletów`, ipa: `dzien˧˩ piao˥˩`},{zh: `站台`, pl: `peron`, ipa: `dżan˥˩ taj˧˥`}], phrases: [{zh: `我要去上海。`, pl: `Jadę do Szanghaju.`, ipa: `ło˧˩ jao˥˩ ciü˥˩ szang˥ xaj˧˩`},{zh: `高铁几点出发？`, pl: `O której odjeżdża szybki pociąg?`, ipa: `gao˥ tie˧˩ dzi˧˩ dien˧˩ chu˥ fa˥`},{zh: `我的座位在哪里？`, pl: `Gdzie jest moje miejsce?`, ipa: `ło˧˩ de dzuo˥˩ łej˥˩ dzaj˥˩ na˧˩ li`},{zh: `车票在这里。`, pl: `Bilet jest tutaj.`, ipa: `cze˥ piao˥˩ dzaj˥˩ dże˥˩ li`},{zh: `火车晚点了吗？`, pl: `Czy pociąg jest opóźniony?`, ipa: `xuo˧˩ cze˥ łan˧˩ dien˧˩ le ma`},{zh: `站台在哪里？`, pl: `Gdzie jest peron?`, ipa: `dżan˥˩ taj˧˥ dzaj˥˩ na˧˩ li`}], grammar: `„去” oznacza „iść/jechać do”, a po nim podajesz miejsce. „我要去上海” to dosłownie „chcę jechać do Szanghaju”, ale w podróży brzmi naturalnie jako „jadę do Szanghaju”. Pamiętaj, że nazwy miast zwykle nie potrzebują przyimka.`, practice: [`Powiedz, że jedziesz do Szanghaju.`,`Zapytaj, o której odjeżdża pociąg.`,`Zapytaj, gdzie jest peron.`,`Powiedz, że twój bilet jest tutaj.`,`Zapytaj, czy pociąg jest opóźniony.`]},{day: 18, title: `Zakupy i pamiątki`, title_native: `购物和纪念品`, focus: `Na targu w Pekinie albo w sklepie z herbatą w Hangzhou chcesz kupić pamiątkę. Nauczysz się pytać o cenę, rozmiar i kolory.`, vocab: [{zh: `买`, pl: `kupować`, ipa: `maj˧˩`},{zh: `卖`, pl: `sprzedawać`, ipa: `maj˥˩`},{zh: `商店`, pl: `sklep`, ipa: `szang˥ dien˥˩`},{zh: `市场`, pl: `targ`, ipa: `szy˥˩ czang˧˥`},{zh: `纪念品`, pl: `pamiątka`, ipa: `dzi˥˩ nien˥˩ pin˧˩`},{zh: `颜色`, pl: `kolor`, ipa: `jen˧˥ se˥˩`},{zh: `红色`, pl: `czerwony`, ipa: `xong˧˥ se˥˩`},{zh: `蓝色`, pl: `niebieski`, ipa: `lan˧˥ se˥˩`},{zh: `小`, pl: `mały`, ipa: `śiao˧˩`},{zh: `大`, pl: `duży`, ipa: `da˥˩`}], phrases: [{zh: `我想买这个。`, pl: `Chciałbym kupić to.`, ipa: `ło˧˩ śiang˧˩ maj˧˩ dże˥˩ ge`},{zh: `有蓝色的吗？`, pl: `Czy jest niebieski?`, ipa: `jou˧˩ lan˧˥ se˥˩ de ma`},{zh: `太大了。`, pl: `To za duże.`, ipa: `taj˥˩ da˥˩ le`},{zh: `有小一点的吗？`, pl: `Czy jest trochę mniejsze?`, ipa: `jou˧˩ śiao˧˩ ji˥ dien˧˩ de ma`},{zh: `可以便宜一点吗？`, pl: `Czy może być trochę taniej?`, ipa: `ke˧˩ ji˧˩ pien˧˥ ji˧ ji˥ dien˧˩ ma`},{zh: `我不要袋子。`, pl: `Nie chcę torby.`, ipa: `ło˧˩ bu˥˩ jao˥˩ daj˥˩ dz`}], grammar: `„一点” oznacza „trochę” i często łagodzi prośbę. „小一点” to „trochę mniejsze”, a „便宜一点” to „trochę taniej”. W zakupach brzmi to naturalniej niż bardzo bezpośrednie żądanie.`, practice: [`Powiedz, że chcesz kupić tę pamiątkę.`,`Zapytaj, czy jest niebieski kolor.`,`Powiedz, że coś jest za duże.`,`Poproś o trochę niższą cenę.`,`Powiedz, że nie potrzebujesz torby.`]},{day: 19, title: `Ubrania i rozmiary`, title_native: `衣服和尺码`, focus: `W centrum handlowym w Shenzhen lub Tajpej chcesz przymierzyć ubranie. Dzisiaj nauczysz się mówić o rozmiarach, kolorach i przymierzaniu.`, vocab: [{zh: `衣服`, pl: `ubrania`, ipa: `ji˥ fu`},{zh: `裤子`, pl: `spodnie`, ipa: `ku˥˩ dz`},{zh: `鞋`, pl: `buty`, ipa: `śie˧˥`},{zh: `衬衫`, pl: `koszula`, ipa: `czen˥˩ szan˥`},{zh: `尺码`, pl: `rozmiar`, ipa: `czy˧˩ ma˧˩`},{zh: `试`, pl: `przymierzać / próbować`, ipa: `szy˥˩`},{zh: `合适`, pl: `pasować`, ipa: `xe˧˥ szy˥˩`},{zh: `太小`, pl: `za małe`, ipa: `taj˥˩ śiao˧˩`},{zh: `太大`, pl: `za duże`, ipa: `taj˥˩ da˥˩`},{zh: `黑色`, pl: `czarny`, ipa: `xej˥ se˥˩`}], phrases: [{zh: `我可以试一下吗？`, pl: `Czy mogę przymierzyć?`, ipa: `ło˧˩ ke˧˩ ji˧˩ szy˥˩ ji˧˥ śia˥˩ ma`},{zh: `有大一点的吗？`, pl: `Czy jest trochę większy rozmiar?`, ipa: `jou˧˩ da˥˩ ji˥ dien˧˩ de ma`},{zh: `有小一点的吗？`, pl: `Czy jest trochę mniejszy rozmiar?`, ipa: `jou˧˩ śiao˧˩ ji˥ dien˧˩ de ma`},{zh: `这个很合适。`, pl: `To bardzo pasuje.`, ipa: `dże˥˩ ge hen˧˩ xe˧˥ szy˥˩`},{zh: `这个太小了。`, pl: `To jest za małe.`, ipa: `dże˥˩ ge taj˥˩ śiao˧˩ le`},{zh: `我要黑色的。`, pl: `Chcę czarne.`, ipa: `ło˧˩ jao˥˩ xej˥ se˥˩ de`}], grammar: `„的” może zastępować rzeczownik, gdy kontekst jest jasny. „黑色的” znaczy „ten czarny / czarne”. W sklepie możesz powiedzieć „我要黑色的”, jeśli sprzedawca wie, że chodzi o koszulę, buty albo torbę.`, practice: [`Zapytaj, czy możesz przymierzyć ubranie.`,`Powiedz, że rozmiar jest za mały.`,`Poproś o większy rozmiar.`,`Powiedz, że chcesz czarne buty.`,`Powiedz, że coś dobrze pasuje.`]},{day: 20, title: `Zwiedzanie i bilety`, title_native: `观光和门票`, focus: `Przy wejściu do Zakazanego Miasta, muzeum albo świątyni musisz kupić bilet i zapytać o godziny otwarcia. Ten dzień uczy języka zwiedzania.`, vocab: [{zh: `博物馆`, pl: `muzeum`, ipa: `bo˧˥ u˥˩ guan˧˩`},{zh: `寺庙`, pl: `świątynia`, ipa: `sy˥˩ miao˥˩`},{zh: `公园`, pl: `park`, ipa: `gong˥ jüen˧˥`},{zh: `门票`, pl: `bilet wstępu`, ipa: `men˧˥ piao˥˩`},{zh: `开放`, pl: `otwarte / otwierać`, ipa: `kaj˥ fang˥˩`},{zh: `关门`, pl: `zamykać`, ipa: `guan˥ men˧˥`},{zh: `拍照`, pl: `robić zdjęcie`, ipa: `paj˥ dżao˥˩`},{zh: `导游`, pl: `przewodnik`, ipa: `dao˧˩ jou˧˥`},{zh: `地图`, pl: `mapa`, ipa: `di˥˩ tu˧˥`},{zh: `入口`, pl: `wejście`, ipa: `żu˥˩ koł˧˩`}], phrases: [{zh: `门票多少钱？`, pl: `Ile kosztuje bilet wstępu?`, ipa: `men˧˥ piao˥˩ duo˥ szao˧˩ cien˧˥`},{zh: `几点开放？`, pl: `O której otwierają?`, ipa: `dzi˧˩ dien˧˩ kaj˥ fang˥˩`},{zh: `几点关门？`, pl: `O której zamykają?`, ipa: `dzi˧˩ dien˧˩ guan˥ men˧˥`},{zh: `可以拍照吗？`, pl: `Czy można robić zdjęcia?`, ipa: `ke˧˩ ji˧˩ paj˥ dżao˥˩ ma`},{zh: `我需要地图。`, pl: `Potrzebuję mapy.`, ipa: `ło˧˩ śü˥ jao˥˩ di˥˩ tu˧˥`},{zh: `入口在哪里？`, pl: `Gdzie jest wejście?`, ipa: `żu˥˩ koł˧˩ dzaj˥˩ na˧˩ li`}], grammar: `„可以…吗？” to bardzo praktyczna struktura do pytania o pozwolenie. „可以拍照吗？” oznacza „czy można robić zdjęcia?”. W miejscach historycznych i świątyniach warto pytać, zamiast zakładać.`, practice: [`Zapytaj o cenę biletu wstępu.`,`Zapytaj, o której muzeum się zamyka.`,`Zapytaj, czy można robić zdjęcia.`,`Poproś o mapę.`,`Zapytaj, gdzie jest wejście.`]},{day: 21, title: `Zdrowie i apteka`, title_native: `健康和药店`, focus: `W aptece w Tajpej albo Szanghaju chcesz kupić lek przeciwbólowy albo powiedzieć, co ci dolega. Nauczysz się prostych zwrotów zdrowotnych.`, vocab: [{zh: `药店`, pl: `apteka`, ipa: `jao˥˩ dien˥˩`},{zh: `药`, pl: `lek`, ipa: `jao˥˩`},{zh: `医生`, pl: `lekarz`, ipa: `ji˥ szeng˥`},{zh: `医院`, pl: `szpital`, ipa: `ji˥ jüen˥˩`},{zh: `头疼`, pl: `ból głowy`, ipa: `toł˧˥ teng˧˥`},{zh: `肚子疼`, pl: `ból brzucha`, ipa: `du˥˩ dz teng˧˥`},{zh: `感冒`, pl: `przeziębienie`, ipa: `gan˧˩ mao˥˩`},{zh: `发烧`, pl: `gorączka`, ipa: `fa˥ szao˥`},{zh: `疼`, pl: `boleć`, ipa: `teng˧˥`},{zh: `帮助`, pl: `pomoc`, ipa: `bang˥ dżu˥˩`}], phrases: [{zh: `我头疼。`, pl: `Boli mnie głowa.`, ipa: `ło˧˩ toł˧˥ teng˧˥`},{zh: `我肚子疼。`, pl: `Boli mnie brzuch.`, ipa: `ło˧˩ du˥˩ dz teng˧˥`},{zh: `我感冒了。`, pl: `Przeziębiłem się.`, ipa: `ło˧˩ gan˧˩ mao˥˩ le`},{zh: `我发烧了。`, pl: `Mam gorączkę.`, ipa: `ło˧˩ fa˥ szao˥ le`},{zh: `我需要药。`, pl: `Potrzebuję leku.`, ipa: `ło˧˩ śü˥ jao˥˩ jao˥˩`},{zh: `附近有医院吗？`, pl: `Czy w pobliżu jest szpital?`, ipa: `fu˥˩ dzin˥ jou˧˩ ji˥ jüen˥˩ ma`}], grammar: `Części ciała często stawia się przed „疼”, aby powiedzieć, co boli. „头疼” to „głowa boli”, czyli „ból głowy”. „了” w „感冒了” i „发烧了” pokazuje, że stan już się pojawił.`, practice: [`Powiedz, że boli cię głowa.`,`Powiedz, że masz gorączkę.`,`Zapytaj, czy w pobliżu jest szpital.`,`Poproś w aptece o lek.`,`Opisz dwa objawy prostymi zdaniami.`]},{day: 22, title: `Nagłe sytuacje i bezpieczeństwo`, title_native: `紧急情况和安全`, focus: `W nagłej sytuacji musisz mówić krótko i jasno. Ten dzień uczy słów związanych z pomocą, policją i zgubionymi rzeczami.`, vocab: [{zh: `紧急`, pl: `nagły / pilny`, ipa: `dzin˧˩ dzi˧˥`},{zh: `救命`, pl: `ratunku`, ipa: `dzioł˥˩ ming˥˩`},{zh: `警察`, pl: `policja`, ipa: `dzing˧˩ cza˧˥`},{zh: `丢了`, pl: `zgubić się`, ipa: `dioł˥ le`},{zh: `钱包`, pl: `portfel`, ipa: `cien˧˥ bao˥`},{zh: `手机`, pl: `telefon komórkowy`, ipa: `szoł˧˩ dzi˥`},{zh: `护照`, pl: `paszport`, ipa: `xu˥˩ dżao˥˩`},{zh: `危险`, pl: `niebezpieczeństwo`, ipa: `łej˥ śien˧˩`},{zh: `安全`, pl: `bezpieczeństwo`, ipa: `an˥ czüen˧˥`},{zh: `帮助`, pl: `pomoc`, ipa: `bang˥ dżu˥˩`}], phrases: [{zh: `救命！`, pl: `Ratunku!`, ipa: `dzioł˥˩ ming˥˩`},{zh: `我需要帮助。`, pl: `Potrzebuję pomocy.`, ipa: `ło˧˩ śü˥ jao˥˩ bang˥ dżu˥˩`},{zh: `我的手机丢了。`, pl: `Zgubiłem telefon.`, ipa: `ło˧˩ de szoł˧˩ dzi˥ dioł˥ le`},{zh: `我的护照丢了。`, pl: `Zgubiłem paszport.`, ipa: `ło˧˩ de xu˥˩ dżao˥˩ dioł˥ le`},{zh: `请叫警察。`, pl: `Proszę wezwać policję.`, ipa: `cing˧˩ dziao˥˩ dzing˧˩ cza˧˥`},{zh: `这里安全吗？`, pl: `Czy tutaj jest bezpiecznie?`, ipa: `dże˥˩ li an˥ czüen˧˥ ma`}], grammar: `„我的…” oznacza „mój/moja/moje”. „我的手机丢了” to gotowy wzór: moje + rzecz + zgubiło się. W stresie takie proste struktury są najłatwiejsze do użycia.`, practice: [`Powiedz, że potrzebujesz pomocy.`,`Powiedz, że zgubiłeś telefon.`,`Poproś, żeby ktoś wezwał policję.`,`Zapytaj, czy miejsce jest bezpieczne.`,`Ułóż zdanie o zgubionym portfelu.`]},{day: 23, title: `Pogoda i plany dnia`, title_native: `天气和一天的计划`, focus: `Pogoda wpływa na zwiedzanie, wycieczki i transport. Nauczysz się mówić o deszczu, upale i prostych planach.`, vocab: [{zh: `天气`, pl: `pogoda`, ipa: `tien˥ ci˥˩`},{zh: `下雨`, pl: `pada deszcz`, ipa: `śia˥˩ jü˧˩`},{zh: `晴天`, pl: `słonecznie`, ipa: `cing˧˥ tien˥`},{zh: `冷`, pl: `zimno`, ipa: `leng˧˩`},{zh: `热`, pl: `gorąco`, ipa: `że˥˩`},{zh: `风`, pl: `wiatr`, ipa: `feng˥`},{zh: `雨伞`, pl: `parasol`, ipa: `jü˧˩ san˧˩`},{zh: `计划`, pl: `plan`, ipa: `dzi˥˩ xua˥˩`},{zh: `今天`, pl: `dzisiaj`, ipa: `dzin˥ tien˥`},{zh: `明天`, pl: `jutro`, ipa: `ming˧˥ tien˥`}], phrases: [{zh: `今天天气怎么样？`, pl: `Jaka jest dzisiaj pogoda?`, ipa: `dzin˥ tien˥ tien˥ ci˥˩ dzem˧ me jang˥˩`},{zh: `今天很热。`, pl: `Dzisiaj jest gorąco.`, ipa: `dzin˥ tien˥ hen˧˩ że˥˩`},{zh: `明天会下雨吗？`, pl: `Czy jutro będzie padać?`, ipa: `ming˧˥ tien˥ xuej˥˩ śia˥˩ jü˧˩ ma`},{zh: `我需要雨伞。`, pl: `Potrzebuję parasola.`, ipa: `ło˧˩ śü˥ jao˥˩ jü˧˩ san˧˩`},{zh: `我们去公园。`, pl: `Idziemy do parku.`, ipa: `ło˧˩ men ciü˥˩ gong˥ jüen˧˥`},{zh: `天气不好。`, pl: `Pogoda jest zła.`, ipa: `tien˥ ci˥˩ bu˥˩ xau˧˩`}], grammar: `„怎么样？” oznacza „jakie jest?” lub „co sądzisz?”. W pytaniu o pogodę działa jak polskie „jaka jest pogoda?”. „会” może wskazywać przyszłość lub możliwość: „会下雨” to „będzie padać / może padać”.`, practice: [`Zapytaj o dzisiejszą pogodę.`,`Powiedz, że jest bardzo gorąco.`,`Zapytaj, czy jutro będzie padać.`,`Powiedz, że potrzebujesz parasola.`,`Ułóż plan dnia z 我们去…`]},{day: 24, title: `Telefon, internet i Wi-Fi`, title_native: `电话，网络和无线网`, focus: `Bez internetu trudno korzystać z map i płatności. Dzisiaj nauczysz się pytać o Wi-Fi, kartę SIM i ładowarkę.`, vocab: [{zh: `手机`, pl: `telefon komórkowy`, ipa: `szoł˧˩ dzi˥`},{zh: `网络`, pl: `internet / sieć`, ipa: `łang˧˩ luo˥˩`},{zh: `无线网`, pl: `Wi-Fi`, ipa: `u˧˥ śien˥˩ łang˧˩`},{zh: `密码`, pl: `hasło`, ipa: `mi˥˩ ma˧˩`},{zh: `充电器`, pl: `ładowarka`, ipa: `czong˥ dien˥˩ ci˥˩`},{zh: `电池`, pl: `bateria`, ipa: `dien˥˩ czy˧˥`},{zh: `卡`, pl: `karta`, ipa: `ka˧˩`},{zh: `电话`, pl: `telefon / rozmowa`, ipa: `dien˥˩ xua˥˩`},{zh: `信号`, pl: `sygnał`, ipa: `śin˥ xao˥˩`},{zh: `坏了`, pl: `zepsute`, ipa: `xuaj˥˩ le`}], phrases: [{zh: `有无线网吗？`, pl: `Czy jest Wi-Fi?`, ipa: `jou˧˩ u˧˥ śien˥˩ łang˧˩ ma`},{zh: `密码是什么？`, pl: `Jakie jest hasło?`, ipa: `mi˥˩ ma˧˩ szy˥˩ szen˧ me`},{zh: `我需要充电器。`, pl: `Potrzebuję ładowarki.`, ipa: `ło˧˩ śü˥ jao˥˩ czong˥ dien˥˩ ci˥˩`},{zh: `我的手机没电了。`, pl: `Mój telefon się rozładował.`, ipa: `ło˧˩ de szoł˧˩ dzi˥ mej˧˥ dien˥˩ le`},{zh: `这里信号不好。`, pl: `Tutaj jest słaby sygnał.`, ipa: `dże˥˩ li śin˥ xao˥˩ bu˥˩ xau˧˩`},{zh: `可以买手机卡吗？`, pl: `Czy można kupić kartę SIM?`, ipa: `ke˧˩ ji˧˩ maj˧˩ szoł˧˩ dzi˥ ka˧˩ ma`}], grammar: `„没” często zaprzecza posiadanie lub istnienie, a „没电了” znaczy dosłownie „nie ma prądu”, czyli bateria padła. To przydatne zdanie w kawiarni, hotelu i na dworcu. „密码是什么？” to prosty sposób zapytania o hasło.`, practice: [`Zapytaj w kawiarni, czy jest Wi-Fi.`,`Zapytaj o hasło.`,`Powiedz, że twój telefon się rozładował.`,`Poproś o ładowarkę.`,`Zapytaj, czy można kupić kartę SIM.`]},{day: 25, title: `Spotkania towarzyskie`, title_native: `社交见面`, focus: `Podczas wycieczki, w barze herbacianym albo w hostelu możesz poznać miejscowych. Nauczysz się prowadzić prostą, uprzejmą rozmowę.`, vocab: [{zh: `聊天`, pl: `rozmawiać`, ipa: `liao˧˥ tien˥`},{zh: `喜欢`, pl: `lubić`, ipa: `śi˧˩ xuan˥`},{zh: `中国`, pl: `Chiny`, ipa: `dżong˥ guo˧˥`},{zh: `台湾`, pl: `Tajwan`, ipa: `taj˧˥ łan˥`},{zh: `城市`, pl: `miasto`, ipa: `czeng˧˥ szy˥˩`},{zh: `漂亮`, pl: `ładny`, ipa: `piao˥˩ liang˥˩`},{zh: `有意思`, pl: `interesujący`, ipa: `jou˧˩ ji˥˩ sy`},{zh: `工作`, pl: `praca`, ipa: `gong˥ dzuo˥˩`},{zh: `旅行`, pl: `podróżować`, ipa: `lü˧˩ śing˧˥`},{zh: `文化`, pl: `kultura`, ipa: `łen˧˥ xua˥˩`}], phrases: [{zh: `你喜欢这里吗？`, pl: `Czy podoba ci się tutaj?`, ipa: `ni˧˩ śi˧˩ xuan˥ dże˥˩ li ma`},{zh: `我很喜欢中国。`, pl: `Bardzo lubię Chiny.`, ipa: `ło˧˩ hen˧˩ śi˧˩ xuan˥ dżong˥ guo˧˥`},{zh: `这个城市很漂亮。`, pl: `To miasto jest bardzo ładne.`, ipa: `dże˥˩ ge czeng˧˥ szy˥˩ hen˧˩ piao˥˩ liang˥˩`},{zh: `你做什么工作？`, pl: `Jaką masz pracę?`, ipa: `ni˧˩ dzuo˥˩ szen˧ me gong˥ dzuo˥˩`},{zh: `我喜欢旅行。`, pl: `Lubię podróżować.`, ipa: `ło˧˩ śi˧˩ xuan˥ lü˧˩ śing˧˥`},{zh: `文化很有意思。`, pl: `Kultura jest bardzo interesująca.`, ipa: `łen˧˥ xua˥˩ hen˧˩ jou˧˩ ji˥˩ sy`}], grammar: `„喜欢” oznacza „lubić” i po nim możesz dodać rzeczownik lub czynność. „我喜欢旅行” znaczy „lubię podróżować”. Do wzmocnienia opinii użyj „很”, na przykład „很漂亮” i „很有意思”.`, practice: [`Powiedz, że lubisz podróżować.`,`Powiedz, że miasto jest ładne.`,`Zapytaj kogoś, czy podoba mu się tutaj.`,`Zapytaj o pracę w uprzejmej rozmowie.`,`Opisz kulturę jako interesującą.`]},{day: 26, title: `Zaproszenia i umawianie planów`, title_native: `邀请和安排计划`, focus: `Chcesz zaprosić znajomego na herbatę, kolację albo spacer po Bundzie w Szanghaju. Dzisiaj ćwiczysz propozycje i odpowiedzi.`, vocab: [{zh: `一起`, pl: `razem`, ipa: `ji˥ ci˧˩`},{zh: `喝`, pl: `pić`, ipa: `xe˥`},{zh: `吃饭`, pl: `jeść posiłek`, ipa: `czy˥ fan˥˩`},{zh: `走走`, pl: `pospacerować`, ipa: `dzoł˧˩ dzoł`},{zh: `晚上`, pl: `wieczorem`, ipa: `łan˧˩ szang˥˩`},{zh: `下午`, pl: `po południu`, ipa: `śia˥˩ u˧˩`},{zh: `有空`, pl: `mieć czas`, ipa: `jou˧˩ kong˥˩`},{zh: `没空`, pl: `nie mieć czasu`, ipa: `mej˧˥ kong˥˩`},{zh: `可以`, pl: `można / móc`, ipa: `ke˧˩ ji˧˩`},{zh: `约`, pl: `umówić się`, ipa: `jüe˥`}], phrases: [{zh: `你有空吗？`, pl: `Masz czas?`, ipa: `ni˧˩ jou˧˩ kong˥˩ ma`},{zh: `我们一起喝茶吧。`, pl: `Napijmy się razem herbaty.`, ipa: `ło˧˩ men ji˥ ci˧˩ xe˥ cza˧˥ ba`},{zh: `晚上一起吃饭吗？`, pl: `Zjemy razem kolację?`, ipa: `łan˧˩ szang˥˩ ji˥ ci˧˩ czy˥ fan˥˩ ma`},{zh: `下午可以吗？`, pl: `Czy po południu pasuje?`, ipa: `śia˥˩ u˧˩ ke˧˩ ji˧˩ ma`},{zh: `我今天没空。`, pl: `Dzisiaj nie mam czasu.`, ipa: `ło˧˩ dzin˥ tien˥ mej˧˥ kong˥˩`},{zh: `明天可以。`, pl: `Jutro pasuje.`, ipa: `ming˧˥ tien˥ ke˧˩ ji˧˩`}], grammar: `„吧” na końcu zdania często zmiękcza propozycję, jak polskie „może” albo „chodźmy”. „我们一起喝茶吧” brzmi naturalnie jako zaproszenie. „有空” dosłownie znaczy „mieć wolną przestrzeń”, czyli mieć czas.`, practice: [`Zapytaj kogoś, czy ma czas.`,`Zaproś kogoś na herbatę.`,`Zaproponuj kolację wieczorem.`,`Powiedz, że dzisiaj nie masz czasu.`,`Zaproponuj jutro jako alternatywę.`]},{day: 27, title: `Opinie i preferencje`, title_native: `意见和偏好`, focus: `W rozmowie z lokalnymi mieszkańcami albo innymi turystami chcesz powiedzieć, co lubisz i co wolisz. Ten dzień rozwija proste opinie.`, vocab: [{zh: `觉得`, pl: `uważać / czuć, że`, ipa: `dzüe˧˥ de`},{zh: `喜欢`, pl: `lubić`, ipa: `śi˧˩ xuan˥`},{zh: `更`, pl: `bardziej`, ipa: `geng˥˩`},{zh: `最好`, pl: `najlepszy`, ipa: `dzuej˥˩ xau˧˩`},{zh: `不错`, pl: `niezły`, ipa: `bu˧˥ cuo˥˩`},{zh: `一般`, pl: `przeciętny`, ipa: `ji˥ ban˥`},{zh: `贵`, pl: `drogi`, ipa: `guej˥˩`},{zh: `便宜`, pl: `tani`, ipa: `pien˧˥ ji˧`},{zh: `方便`, pl: `wygodny`, ipa: `fang˥˩ bien˥˩`},{zh: `麻烦`, pl: `kłopotliwy`, ipa: `ma˧˥ fan`}], phrases: [{zh: `我觉得很好。`, pl: `Uważam, że jest bardzo dobrze.`, ipa: `ło˧˩ dzüe˧˥ de hen˧˩ xau˧˩`},{zh: `这个不错。`, pl: `To jest niezłe.`, ipa: `dże˥˩ ge bu˧˥ cuo˥˩`},{zh: `我更喜欢茶。`, pl: `Wolę herbatę.`, ipa: `ło˧˩ geng˥˩ śi˧˩ xuan˥ cza˧˥`},{zh: `这里很方便。`, pl: `Tutaj jest bardzo wygodnie.`, ipa: `dże˥˩ li hen˧˩ fang˥˩ bien˥˩`},{zh: `这个有点贵。`, pl: `To jest trochę drogie.`, ipa: `dże˥˩ ge jou˧˩ dien˧˩ guej˥˩`},{zh: `哪个最好？`, pl: `Który jest najlepszy?`, ipa: `na˧˩ ge dzuej˥˩ xau˧˩`}], grammar: `„我觉得…” to bezpieczny sposób wyrażania opinii: „uważam, że…”. „有点” oznacza „trochę”, często w lekko negatywnym sensie, na przykład „有点贵” — trochę drogo. „更喜欢” znaczy „bardziej lubię”, czyli „wolę”.`, practice: [`Powiedz, że wolisz herbatę od kawy.`,`Wyraź opinię o restauracji.`,`Powiedz, że coś jest trochę drogie.`,`Zapytaj, który wariant jest najlepszy.`,`Opisz metro jako wygodne.`]},{day: 28, title: `Praca, hobby i codzienność`, title_native: `工作，爱好和日常`, focus: `Gdy rozmowa staje się bardziej osobista, możesz opowiedzieć o pracy, hobby i codziennym życiu. Nauczysz się kilku prostych zdań o sobie.`, vocab: [{zh: `工作`, pl: `praca`, ipa: `gong˥ dzuo˥˩`},{zh: `学习`, pl: `uczyć się`, ipa: `śüe˧˥ śi˧˥`},{zh: `语言`, pl: `język`, ipa: `jü˧˩ jen˧˥`},{zh: `中文`, pl: `język chiński`, ipa: `dżong˥ łen˧˥`},{zh: `英文`, pl: `angielski`, ipa: `jing˥ łen˧˥`},{zh: `爱好`, pl: `hobby`, ipa: `aj˥˩ xao˥˩`},{zh: `音乐`, pl: `muzyka`, ipa: `jin˥ jüe˥˩`},{zh: `电影`, pl: `film`, ipa: `dien˥˩ jing˧˩`},{zh: `运动`, pl: `sport`, ipa: `jün˥˩ dong˥˩`},{zh: `每天`, pl: `codziennie`, ipa: `mej˧˩ tien˥`}], phrases: [{zh: `我学习中文。`, pl: `Uczę się chińskiego.`, ipa: `ło˧˩ śüe˧˥ śi˧˥ dżong˥ łen˧˥`},{zh: `我的工作很忙。`, pl: `Moja praca jest bardzo zajęta.`, ipa: `ło˧˩ de gong˥ dzuo˥˩ hen˧˩ mang˧˥`},{zh: `我的爱好是音乐。`, pl: `Moje hobby to muzyka.`, ipa: `ło˧˩ de aj˥˩ xao˥˩ szy˥˩ jin˥ jüe˥˩`},{zh: `我喜欢看电影。`, pl: `Lubię oglądać filmy.`, ipa: `ło˧˩ śi˧˩ xuan˥ kan˥˩ dien˥˩ jing˧˩`},{zh: `你会说英文吗？`, pl: `Czy mówisz po angielsku?`, ipa: `ni˧˩ xuej˥˩ szuo˥ jing˥ łen˧˥ ma`},{zh: `我每天学习。`, pl: `Uczę się codziennie.`, ipa: `ło˧˩ mej˧˩ tien˥ śüe˧˥ śi˧˥`}], grammar: `„会” oznacza umiejętność albo możliwość: „你会说英文吗？” to „czy umiesz mówić po angielsku?”. „说” znaczy „mówić”, a nazwa języka idzie po nim. „我会说一点中文” będzie znaczyło „mówię trochę po chińsku”.`, practice: [`Powiedz, że uczysz się chińskiego.`,`Zapytaj kogoś, czy mówi po angielsku.`,`Powiedz, że lubisz oglądać filmy.`,`Opisz swoje hobby jednym zdaniem.`,`Powiedz, że uczysz się codziennie.`]},{day: 29, title: `Łączenie zdań i opowiadanie`, title_native: `连接句子和讲述`, focus: `Teraz potrafisz powiedzieć więcej niż jedno zdanie naraz. Nauczysz się prostych łączników, żeby opowiedzieć o dniu w podróży.`, vocab: [{zh: `然后`, pl: `potem`, ipa: `żan˧˥ xoł˥˩`},{zh: `因为`, pl: `ponieważ`, ipa: `jin˥ łej˥˩`},{zh: `所以`, pl: `więc`, ipa: `suo˧˩ ji˧˩`},{zh: `但是`, pl: `ale`, ipa: `dan˥˩ szy˥˩`},{zh: `和`, pl: `i`, ipa: `xe˧˥`},{zh: `或者`, pl: `albo`, ipa: `xuo˥˩ dże˧˩`},{zh: `先`, pl: `najpierw`, ipa: `śien˥`},{zh: `再`, pl: `następnie`, ipa: `dzaj˥˩`},{zh: `已经`, pl: `już`, ipa: `ji˧˩ dzing˥`},{zh: `还`, pl: `jeszcze`, ipa: `xaj˧˥`}], phrases: [{zh: `我先去酒店。`, pl: `Najpierw idę do hotelu.`, ipa: `ło˧˩ śien˥ ciü˥˩ dzioł˧˩ dien˥˩`},{zh: `然后去餐厅。`, pl: `Potem idę do restauracji.`, ipa: `żan˧˥ xoł˥˩ ciü˥˩ can˥ ting˥`},{zh: `因为下雨，所以我坐地铁。`, pl: `Ponieważ pada, jadę metrem.`, ipa: `jin˥ łej˥˩ śia˥˩ jü˧˩ suo˧˩ ji˧˩ ło˧˩ dzuo˥˩ di˥˩ tie˧˩`},{zh: `我想去，但是没时间。`, pl: `Chcę iść, ale nie mam czasu.`, ipa: `ło˧˩ śiang˧˩ ciü˥˩ dan˥˩ szy˥˩ mej˧˥ szy˧˥ dzien˥`},{zh: `我已经买票了。`, pl: `Już kupiłem bilet.`, ipa: `ło˧˩ ji˧˩ dzing˥ maj˧˩ piao˥˩ le`},{zh: `我还需要地图。`, pl: `Nadal potrzebuję mapy.`, ipa: `ło˧˩ xaj˧˥ śü˥ jao˥˩ di˥˩ tu˧˥`}], grammar: `„因为…所以…” odpowiada polskiemu „ponieważ… więc…”. W chińskim często używa się obu części razem, choć w polskim zwykle jedna wystarcza. „先…然后…” pomaga opisać kolejność działań w planie dnia.`, practice: [`Opowiedz plan: najpierw hotel, potem restauracja.`,`Użyj 因为 i 所以 w zdaniu o deszczu.`,`Powiedz, że chcesz iść, ale nie masz czasu.`,`Powiedz, że już kupiłeś bilet.`,`Opisz swój dzień w podróży w czterech krótkich zdaniach.`]},{day: 30, title: `Powtórka podróżna i pewność w rozmowie`, title_native: `旅行复习和自信交流`, focus: `Ostatni dzień łączy najważniejsze umiejętności: hotel, jedzenie, transport, zakupy i prośby o pomoc. Celem jest szybka, praktyczna komunikacja w realnej podróży.`, vocab: [{zh: `旅行`, pl: `podróż`, ipa: `lü˧˩ śing˧˥`},{zh: `帮助`, pl: `pomoc`, ipa: `bang˥ dżu˥˩`},{zh: `问题`, pl: `problem / pytanie`, ipa: `łen˥˩ ti˧˥`},{zh: `地方`, pl: `miejsce`, ipa: `di˥˩ fang`},{zh: `推荐`, pl: `polecać`, ipa: `tuej˥ dzien˥`},{zh: `附近`, pl: `w pobliżu`, ipa: `fu˥˩ dzin˥`},{zh: `重要`, pl: `ważny`, ipa: `dżong˥˩ jao˥˩`},{zh: `简单`, pl: `prosty`, ipa: `dzien˧˩ dan˥`},{zh: `慢慢`, pl: `powoli`, ipa: `man˥˩ man˥˩`},{zh: `再说`, pl: `powiedzieć jeszcze raz`, ipa: `dzaj˥˩ szuo˥`}], phrases: [{zh: `请慢慢说。`, pl: `Proszę mówić powoli.`, ipa: `cing˧˩ man˥˩ man˥˩ szuo˥`},{zh: `请再说一遍。`, pl: `Proszę powtórzyć jeszcze raz.`, ipa: `cing˧˩ dzaj˥˩ szuo˥ ji˥ bien˥˩`},{zh: `附近有什么推荐？`, pl: `Co polecasz w pobliżu?`, ipa: `fu˥˩ dzin˥ jou˧˩ szen˧ me tuej˥ dzien˥`},{zh: `我有一个问题。`, pl: `Mam jedno pytanie.`, ipa: `ło˧˩ jou˧˩ ji˧˥ ge łen˥˩ ti˧˥`},{zh: `这个地方在哪里？`, pl: `Gdzie jest to miejsce?`, ipa: `dże˥˩ ge di˥˩ fang dzaj˥˩ na˧˩ li`},{zh: `谢谢你的帮助。`, pl: `Dziękuję za twoją pomoc.`, ipa: `śje˥ śje ni˧˩ de bang˥ dżu˥˩`}], grammar: `Gdy nie rozumiesz, nie musisz przechodzić na angielski od razu. „请慢慢说” i „请再说一遍” często wystarczą, żeby rozmówca zwolnił albo powtórzył. To bardzo ważna strategia dla początkującego podróżnika.`, practice: [`Poproś kogoś, żeby mówił powoli.`,`Poproś o powtórzenie zdania.`,`Zapytaj, co warto zobaczyć w pobliżu.`,`Powiedz, że masz jedno pytanie.`,`Podziękuj komuś za pomoc i zakończ rozmowę.`]}];

var CONVERSATIONS_PL_ZH = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w kawiarni w Szanghaju niedaleko stacji metra. Chcesz zamówić kawę na wynos bez cukru i zapytać, czy można zapłacić kodem QR.`, lines: [{who: `them`, zh: `你好，请问要什么？`, pl: `Dzień dobry, co podać?`},{who: `you`, zh: `你好，我要一杯咖啡。`, pl: `Dzień dobry, poproszę jedną kawę.`},{who: `them`, zh: `热的还是冰的？`, pl: `Gorącą czy z lodem?`},{who: `you`, zh: `热的，不要糖。`, pl: `Gorącą, bez cukru.`},{who: `them`, zh: `要大杯吗？`, pl: `Czy ma być duża?`},{who: `you`, zh: `对，大杯。`, pl: `Tak, duża.`},{who: `them`, zh: `在这里喝还是外带？`, pl: `Na miejscu czy na wynos?`},{who: `you`, zh: `外带，可以吗？`, pl: `Na wynos, czy można?`},{who: `them`, zh: `可以，一共二十块。`, pl: `Można, razem dwadzieścia juanów.`},{who: `you`, zh: `可以扫码付款吗？`, pl: `Czy mogę zapłacić skanem kodu?`},{who: `them`, zh: `可以，请扫这里。`, pl: `Można, proszę zeskanować tutaj.`},{who: `you`, zh: `谢谢。`, pl: `Dziękuję.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Kantonie. Masz rezerwację i chcesz zapytać o śniadanie oraz windę.`, lines: [{who: `them`, zh: `您好，欢迎光临。`, pl: `Dzień dobry, witamy.`},{who: `you`, zh: `您好，我有预订。`, pl: `Dzień dobry, mam rezerwację.`},{who: `them`, zh: `请给我您的护照。`, pl: `Proszę dać mi paszport.`},{who: `you`, zh: `我的护照在这里。`, pl: `Mój paszport jest tutaj.`},{who: `them`, zh: `谢谢，您要入住吗？`, pl: `Dziękuję, chce się pan/pani zameldować?`},{who: `you`, zh: `对，我要入住。`, pl: `Tak, chcę się zameldować.`},{who: `them`, zh: `您的房间在八楼。`, pl: `Pana/pani pokój jest na ósmym piętrze.`},{who: `you`, zh: `电梯在哪里？`, pl: `Gdzie jest winda?`},{who: `them`, zh: `电梯在右边。`, pl: `Winda jest po prawej.`},{who: `you`, zh: `早餐几点？`, pl: `O której jest śniadanie?`},{who: `them`, zh: `早餐七点到十点。`, pl: `Śniadanie jest od siódmej do dziesiątej.`},{who: `you`, zh: `谢谢你的帮助。`, pl: `Dziękuję za pomoc.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Jesteś w Pekinie i próbujesz znaleźć wejście do muzeum. Pokazujesz adres przechodniowi i prosisz o prostą wskazówkę.`, lines: [{who: `you`, zh: `不好意思，可以帮我吗？`, pl: `Przepraszam, czy możesz mi pomóc?`},{who: `them`, zh: `可以，什么问题？`, pl: `Mogę, jaki problem?`},{who: `you`, zh: `这个地址在哪里？`, pl: `Gdzie jest ten adres?`},{who: `them`, zh: `在前面，不远。`, pl: `Jest z przodu, niedaleko.`},{who: `you`, zh: `我怎么走？`, pl: `Jak mam iść?`},{who: `them`, zh: `一直走，然后往左走。`, pl: `Idź prosto, potem w lewo.`},{who: `you`, zh: `入口在哪里？`, pl: `Gdzie jest wejście?`},{who: `them`, zh: `入口在右边。`, pl: `Wejście jest po prawej.`},{who: `you`, zh: `可以拍照吗？`, pl: `Czy można robić zdjęcia?`},{who: `them`, zh: `里面可以，外面也可以。`, pl: `W środku można, na zewnątrz też.`},{who: `you`, zh: `谢谢，请慢慢说一遍。`, pl: `Dziękuję, proszę powtórzyć powoli.`},{who: `them`, zh: `一直走，然后往左走。`, pl: `Prosto, potem w lewo.`}]},{id: 4, title: `W restauracji w Chengdu`, scene: `Siadasz w restauracji w Chengdu, gdzie wiele dań jest ostrych. Chcesz poprosić o menu, zamówić ryż i kurczaka oraz upewnić się, że jedzenie nie będzie za ostre.`, lines: [{who: `them`, zh: `你好，几位？`, pl: `Dzień dobry, ile osób?`},{who: `you`, zh: `一位。`, pl: `Jedna osoba.`},{who: `them`, zh: `请坐。`, pl: `Proszę usiąść.`},{who: `you`, zh: `请给我菜单。`, pl: `Proszę dać mi menu.`},{who: `them`, zh: `好的，这是菜单。`, pl: `Dobrze, oto menu.`},{who: `you`, zh: `这个鸡肉辣吗？`, pl: `Czy ten kurczak jest ostry?`},{who: `them`, zh: `有一点辣。`, pl: `Jest trochę ostry.`},{who: `you`, zh: `不要太辣，可以吗？`, pl: `Nie za ostro, czy można?`},{who: `them`, zh: `可以。`, pl: `Można.`},{who: `you`, zh: `我要鸡肉和米饭。`, pl: `Poproszę kurczaka i ryż.`},{who: `them`, zh: `好的，还要什么？`, pl: `Dobrze, coś jeszcze?`},{who: `you`, zh: `不要了，谢谢。`, pl: `Nie, dziękuję.`}]},{id: 5, title: `Kupowanie biletu na metro`, scene: `Jesteś przy automacie biletowym w Tajpej, ale nie rozumiesz wszystkich opcji. Pytasz pracownika stacji o bilet i przesiadkę.`, lines: [{who: `you`, zh: `不好意思，我需要帮助。`, pl: `Przepraszam, potrzebuję pomocy.`},{who: `them`, zh: `好的，您要去哪里？`, pl: `Dobrze, dokąd pan/pani jedzie?`},{who: `you`, zh: `我要去市中心。`, pl: `Chcę jechać do centrum.`},{who: `them`, zh: `您可以坐这条线。`, pl: `Może pan/pani jechać tą linią.`},{who: `you`, zh: `我要一张票。`, pl: `Chcę jeden bilet.`},{who: `them`, zh: `二十块钱。`, pl: `Dwadzieścia juanów.`},{who: `you`, zh: `在哪里换乘？`, pl: `Gdzie się przesiąść?`},{who: `them`, zh: `在下一站换乘。`, pl: `Proszę przesiąść się na następnej stacji.`},{who: `you`, zh: `下一站是什么？`, pl: `Jaka jest następna stacja?`},{who: `them`, zh: `下一站是中山站。`, pl: `Następna stacja to Zhongshan.`},{who: `you`, zh: `谢谢，我明白了。`, pl: `Dziękuję, rozumiem.`},{who: `them`, zh: `不客气。`, pl: `Nie ma za co.`}]},{id: 6, title: `Zakupy na targu`, scene: `Jesteś na targu z pamiątkami w Xi’an. Podoba ci się mała torba, ale chcesz zapytać o kolor i poprosić o niższą cenę.`, lines: [{who: `them`, zh: `你好，看看吧。`, pl: `Dzień dobry, proszę popatrzeć.`},{who: `you`, zh: `你好，我想买这个。`, pl: `Dzień dobry, chciałbym kupić to.`},{who: `them`, zh: `这个很好，五十块。`, pl: `To jest bardzo dobre, pięćdziesiąt juanów.`},{who: `you`, zh: `有蓝色的吗？`, pl: `Czy jest niebieskie?`},{who: `them`, zh: `有，在这里。`, pl: `Jest, tutaj.`},{who: `you`, zh: `多少钱一个？`, pl: `Ile za jedną sztukę?`},{who: `them`, zh: `五十块一个。`, pl: `Pięćdziesiąt juanów za sztukę.`},{who: `you`, zh: `太贵了，可以便宜一点吗？`, pl: `Za drogo, czy może być trochę taniej?`},{who: `them`, zh: `四十块，可以。`, pl: `Czterdzieści juanów, może być.`},{who: `you`, zh: `好，我要这个。`, pl: `Dobrze, biorę to.`},{who: `them`, zh: `要袋子吗？`, pl: `Czy chce pan/pani torbę?`},{who: `you`, zh: `不要袋子，谢谢。`, pl: `Nie chcę torby, dziękuję.`}]},{id: 7, title: `W aptece`, scene: `W Tajpej boli cię głowa i chcesz kupić lek. Musisz powiedzieć objaw i zapytać, czy w pobliżu jest szpital, gdyby było gorzej.`, lines: [{who: `them`, zh: `你好，需要什么？`, pl: `Dzień dobry, czego pan/pani potrzebuje?`},{who: `you`, zh: `你好，我头疼。`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, zh: `你发烧了吗？`, pl: `Czy ma pan/pani gorączkę?`},{who: `you`, zh: `没有发烧。`, pl: `Nie mam gorączki.`},{who: `them`, zh: `你需要这个药。`, pl: `Potrzebuje pan/pani tego leku.`},{who: `you`, zh: `这个安全吗？`, pl: `Czy to jest bezpieczne?`},{who: `them`, zh: `对，很安全。`, pl: `Tak, bardzo bezpieczne.`},{who: `you`, zh: `多少钱？`, pl: `Ile kosztuje?`},{who: `them`, zh: `三十块钱。`, pl: `Trzydzieści juanów.`},{who: `you`, zh: `附近有医院吗？`, pl: `Czy w pobliżu jest szpital?`},{who: `them`, zh: `有，在前面。`, pl: `Jest, z przodu.`},{who: `you`, zh: `谢谢你的帮助。`, pl: `Dziękuję za pomoc.`}]},{id: 8, title: `Rozmowa z lokalną osobą`, scene: `Siedzisz w herbaciarni w Hangzhou i rozmawiasz z lokalną osobą. Chcesz powiedzieć, że jesteś z Polski, uczysz się chińskiego i podoba ci się miasto.`, lines: [{who: `you`, zh: `你好，可以坐这里吗？`, pl: `Dzień dobry, czy mogę tu usiąść?`},{who: `them`, zh: `可以，请坐。`, pl: `Można, proszę usiąść.`},{who: `you`, zh: `谢谢，我是波兰人。`, pl: `Dziękuję, jestem z Polski.`},{who: `them`, zh: `很高兴认识你。`, pl: `Miło cię poznać.`},{who: `you`, zh: `我也很高兴认识你。`, pl: `Mnie też miło cię poznać.`},{who: `them`, zh: `你会说中文吗？`, pl: `Czy mówisz po chińsku?`},{who: `you`, zh: `我会说一点中文。`, pl: `Mówię trochę po chińsku.`},{who: `them`, zh: `你喜欢这里吗？`, pl: `Czy podoba ci się tutaj?`},{who: `you`, zh: `我很喜欢，这个城市很漂亮。`, pl: `Bardzo mi się podoba, to miasto jest piękne.`},{who: `them`, zh: `你喜欢喝茶吗？`, pl: `Lubisz pić herbatę?`},{who: `you`, zh: `喜欢，我更喜欢绿茶。`, pl: `Lubię, wolę zieloną herbatę.`},{who: `them`, zh: `欢迎你来杭州。`, pl: `Witamy cię w Hangzhou.`}]}];